import{c as n,S as i,j as h,m as a}from"./chunks/framework.8aa1YH_s.js";const u=JSON.parse('{"title":"Thi thử Tốt nghiệp THPT","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/thi-tnthpt.md","filePath":"hoc-vien/thi-tnthpt.md","lastUpdated":0}'),l={name:"hoc-vien/thi-tnthpt.md"};function o(r,t,c,e,g,s){return i(),h("div",null,[...t[0]||(t[0]=[a('<h1 id="thi-thu-tot-nghiep-thpt" tabindex="-1">Thi thử Tốt nghiệp THPT <a class="header-anchor" href="#thi-thu-tot-nghiep-thpt" aria-label="Permalink to “Thi thử Tốt nghiệp THPT”">​</a></h1><p><strong>Đường dẫn (làm bài):</strong> <code>https://lamsonedutech.vn/luyen-tap/totnghiep-thpt/:idCourse</code></p><h2 id="ve-ky-thi-tot-nghiep-thpt" tabindex="-1">Về kỳ thi Tốt nghiệp THPT <a class="header-anchor" href="#ve-ky-thi-tot-nghiep-thpt" aria-label="Permalink to “Về kỳ thi Tốt nghiệp THPT”">​</a></h2><p>Kỳ thi do <strong>Bộ Giáo dục &amp; Đào tạo</strong> tổ chức hằng năm cho học sinh lớp 12, dùng để:</p><ul><li>Xét tốt nghiệp THPT.</li><li>Một số trường ĐH dùng để xét tuyển.</li></ul><p>LamSơn Edutech cung cấp <strong>đề thi mẫu</strong> mô phỏng đúng cấu trúc đề minh họa của Bộ.</p><h2 id="cac-mon-thi-ho-tro-tren-he-thong" tabindex="-1">Các môn thi hỗ trợ trên hệ thống <a class="header-anchor" href="#cac-mon-thi-ho-tro-tren-he-thong" aria-label="Permalink to “Các môn thi hỗ trợ trên hệ thống”">​</a></h2><table tabindex="0"><thead><tr><th>Môn</th><th>Mã</th><th>Dạng câu chủ yếu</th><th style="text-align:center;">Số câu</th><th style="text-align:center;">Thời gian</th></tr></thead><tbody><tr><td>Toán</td><td>TOAN</td><td>Trắc nghiệm + Đúng/Sai + Trả lời ngắn</td><td style="text-align:center;">22-50</td><td style="text-align:center;">90 phút</td></tr><tr><td>Ngữ văn</td><td>VAN</td><td>Đọc hiểu + Tự luận</td><td style="text-align:center;">-</td><td style="text-align:center;">120 phút</td></tr><tr><td>Tiếng Anh</td><td>(Tùy năm)</td><td>Trắc nghiệm</td><td style="text-align:center;">50</td><td style="text-align:center;">60 phút</td></tr><tr><td>Vật Lí</td><td>LI</td><td>Trắc nghiệm + Đúng/Sai + Trả lời ngắn</td><td style="text-align:center;">40</td><td style="text-align:center;">50 phút</td></tr><tr><td>Hóa học</td><td>HOA</td><td>Trắc nghiệm + Đúng/Sai + Trả lời ngắn</td><td style="text-align:center;">40</td><td style="text-align:center;">50 phút</td></tr><tr><td>Sinh học</td><td>SINH</td><td>Trắc nghiệm + Đúng/Sai + Trả lời ngắn</td><td style="text-align:center;">40</td><td style="text-align:center;">50 phút</td></tr><tr><td>Lịch sử</td><td>SU</td><td>Trắc nghiệm + Đúng/Sai + Trả lời ngắn</td><td style="text-align:center;">40</td><td style="text-align:center;">50 phút</td></tr><tr><td>Địa lí</td><td>DIA</td><td>Trắc nghiệm + Đúng/Sai + Trả lời ngắn</td><td style="text-align:center;">40</td><td style="text-align:center;">50 phút</td></tr></tbody></table><blockquote><p>Số câu và cấu trúc có thể thay đổi theo năm. Hệ thống cập nhật theo đề minh họa mới nhất của Bộ.</p></blockquote><h2 id="tim-đe-thi-thu-o-đau" tabindex="-1">Tìm đề thi thử ở đâu? <a class="header-anchor" href="#tim-đe-thi-thu-o-đau" aria-label="Permalink to “Tìm đề thi thử ở đâu?”">​</a></h2><ul><li>Trang chủ → <strong>&quot;Thi thử Tốt nghiệp THPT&quot;</strong>.</li><li>Trong khóa &quot;Tốt nghiệp THPT 2026&quot; → mục <strong>Đề thi thực chiến</strong>.</li><li>Menu <strong>Bộ đề thi → Tốt nghiệp THPT 2026</strong>.</li></ul><h2 id="truoc-khi-vao-thi" tabindex="-1">Trước khi vào thi <a class="header-anchor" href="#truoc-khi-vao-thi" aria-label="Permalink to “Trước khi vào thi”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Mô phỏng đúng phòng thi thật</p><ul><li>Ngồi yên tĩnh, không có người làm phiền trong <strong>đúng số phút quy định</strong>.</li><li>Chuẩn bị <strong>giấy nháp</strong>, <strong>bút</strong>, <strong>máy tính cầm tay Casio/Vinacal được phép</strong>.</li><li>Đối với Ngữ văn: cần giấy A4 để <strong>viết tự luận</strong>, sau đó scan/chụp upload (nếu đề có phần tự luận).</li><li>Internet ổn định, đủ pin / cắm sạc.</li></ul></div><h2 id="giao-dien-lam-bai" tabindex="-1">Giao diện làm bài <a class="header-anchor" href="#giao-dien-lam-bai" aria-label="Permalink to “Giao diện làm bài”">​</a></h2><p>Tương tự đề HSA/TSA, có:</p><ul><li><strong>Đồng hồ đếm ngược</strong> (theo môn).</li><li><strong>Bảng câu hỏi</strong> bên phải - màu sắc trạng thái.</li><li><strong>Câu trước / Câu tiếp</strong>, <strong>Đánh dấu</strong>.</li></ul><h3 id="dang-cau-hoi-theo-đe-minh-hoa-moi" tabindex="-1">Dạng câu hỏi theo đề minh họa mới <a class="header-anchor" href="#dang-cau-hoi-theo-đe-minh-hoa-moi" aria-label="Permalink to “Dạng câu hỏi theo đề minh họa mới”">​</a></h3><p>Đề Toán/Lý/Hóa/Sinh/Sử/Địa thường có 3 phần:</p><p><strong>Phần I - Trắc nghiệm 4 đáp án (1 đáp án đúng)</strong></p><ul><li>~ 12-18 câu.</li><li>Đếm điểm: mỗi câu đúng + 0.25 điểm (hoặc theo cấu hình đề).</li></ul><p><strong>Phần II - Đúng/Sai 4 ý (a/b/c/d)</strong></p><ul><li>~ 4 câu, mỗi câu 4 ý.</li><li>Cách tính điểm: <ul><li>Đúng 1 ý: 0.1 điểm</li><li>Đúng 2 ý: 0.25 điểm</li><li>Đúng 3 ý: 0.5 điểm</li><li>Đúng cả 4 ý: 1.0 điểm</li></ul></li><li>(Số liệu cụ thể theo quy chế từng năm.)</li></ul><p><strong>Phần III - Trả lời ngắn (điền số)</strong></p><ul><li>~ 6 câu.</li><li>Gõ số (nguyên hoặc thập phân) vào ô.</li><li>Sai định dạng = sai câu.</li></ul><h3 id="ngu-van" tabindex="-1">Ngữ văn <a class="header-anchor" href="#ngu-van" aria-label="Permalink to “Ngữ văn”">​</a></h3><ul><li><strong>Phần Đọc hiểu</strong> (trắc nghiệm + câu hỏi mở).</li><li><strong>Phần Tự luận</strong> (nghị luận xã hội + nghị luận văn học).</li><li>Cần viết tự luận → upload ảnh / file scan / hoặc gõ trực tiếp vào ô lớn.</li></ul><h2 id="ket-qua" tabindex="-1">Kết quả <a class="header-anchor" href="#ket-qua" aria-label="Permalink to “Kết quả”">​</a></h2><p>Trang kết quả hiển thị:</p><h3 id="tong-điem-mon" tabindex="-1">Tổng điểm môn <a class="header-anchor" href="#tong-điem-mon" aria-label="Permalink to “Tổng điểm môn”">​</a></h3><ul><li>Quy đổi về <strong>thang 10</strong>.</li><li>Đối chiếu với phổ điểm các năm trước (nếu hệ thống tích hợp).</li></ul><h3 id="phan-tich-chi-tiet" tabindex="-1">Phân tích chi tiết <a class="header-anchor" href="#phan-tich-chi-tiet" aria-label="Permalink to “Phân tích chi tiết”">​</a></h3><ul><li>Tỷ lệ đúng theo <strong>từng chương</strong> (vd Toán: Hàm số 80%, Lượng giác 50%, ...).</li><li>Phần I / II / III: bao nhiêu điểm mỗi phần.</li><li>Câu sai nhiều nhất.</li></ul><h3 id="so-sanh" tabindex="-1">So sánh <a class="header-anchor" href="#so-sanh" aria-label="Permalink to “So sánh”">​</a></h3><ul><li>Với điểm trung bình của tất cả học viên cùng đề.</li><li>Xếp hạng (nếu công khai).</li></ul><h3 id="xep-loai" tabindex="-1">Xếp loại <a class="header-anchor" href="#xep-loai" aria-label="Permalink to “Xếp loại”">​</a></h3><ul><li>Vd: 8.5 → &quot;Giỏi&quot;; 6.5 → &quot;Khá&quot;; 4.5 → &quot;Trung bình&quot;.</li><li>Đối chiếu <strong>điểm chuẩn các trường ĐH</strong> với khối thi tổ hợp môn của bạn.</li></ul><h2 id="to-hop-mon-khoi-thi" tabindex="-1">Tổ hợp môn (Khối thi) <a class="header-anchor" href="#to-hop-mon-khoi-thi" aria-label="Permalink to “Tổ hợp môn (Khối thi)”">​</a></h2><p>Bạn có thể làm thi thử <strong>theo tổ hợp</strong> (vd: A00 = Toán-Lý-Hóa, B00 = Toán-Hóa-Sinh, ...).</p><ol><li>Vào <strong>Bộ đề thi → Tổ hợp</strong>.</li><li>Chọn tổ hợp của bạn.</li><li>Làm 3 đề mẫu tương ứng - hệ thống cộng điểm tổ hợp tự động.</li></ol><h2 id="chien-luoc-on-thi" tabindex="-1">Chiến lược ôn thi <a class="header-anchor" href="#chien-luoc-on-thi" aria-label="Permalink to “Chiến lược ôn thi”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Luyện theo tuần</p><ul><li><strong>Tuần 1-2</strong>: làm 1 đề/môn, ghi nhận điểm gốc.</li><li><strong>Tuần 3-8</strong>: học chuyên đề yếu + làm bài tập từng chương.</li><li><strong>Tuần 9-12</strong>: làm full đề (1-2 đề/tuần), bám sát điều kiện thi thật.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Phần Đúng/Sai - cẩn thận</p><ul><li>Đừng tích đại - <strong>đúng nửa vẫn ăn nửa điểm</strong>, nhưng sai có thể &quot;kéo&quot; cả câu xuống thấp.</li><li>Đọc kỹ từng ý, giải nháp rồi mới tích.</li></ul></div><div class="tip custom-block"><p class="custom-block-title">Quản lý thời gian</p><ul><li><strong>Lý/Hóa/Sinh/Sử/Địa (50 phút - 40 câu)</strong>: trung bình ~1.25 phút/câu.</li><li><strong>Toán (90 phút)</strong>: phần I (1-1.5p), phần II-III (3-5p mỗi câu).</li><li><strong>Đừng dừng quá 5 phút ở 1 câu</strong> - khoanh đại, đánh dấu, làm câu khác trước.</li></ul></div><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Đề thi thử có giống đề thi thật không?</strong> → Bám sát <strong>đề minh họa</strong> mới nhất của Bộ GD&amp;ĐT, độ khó tương đương. Đề thật mỗi năm có thay đổi nhỏ nhưng cấu trúc giống.</p><p><strong>Tôi học khối D - không thấy đề tiếng Anh?</strong> → Tùy phiên bản hệ thống. Liên hệ trung tâm để kiểm tra hoặc đợi cập nhật.</p><p><strong>Bài Ngữ văn - tôi viết tay rồi chụp lên, ai chấm?</strong> → Giáo viên chấm tay. Thời gian chấm 1-3 ngày làm việc. Sau đó vào <strong>Lịch sử</strong> xem điểm + nhận xét.</p><p><strong>Điểm tôi 8.0/10 - vào được trường nào?</strong> → Hệ thống có thể hiển thị <strong>gợi ý các trường có điểm chuẩn phù hợp</strong>. Cần xét cả tổ hợp (3 môn) và xét tuyển khác (ĐGNL/ĐGTD).</p><p><strong>Tôi muốn luyện riêng phần Đúng/Sai cho Toán?</strong> → Vào <a href="./luyen-tap">Luyện tập theo chuyên đề</a> và lọc theo dạng bài. Nhiều khóa có chuyên đề riêng cho &quot;Dạng câu đúng/sai&quot;.</p>',49)])])}const p=n(l,[["render",o]]);export{u as __pageData,p as default};
